import{_ as b,o as a,c as e,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"乐园的巫女","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/乐园的巫女.md","filePath":"4.资源分区/1.血统与训练/3.心智类/乐园的巫女.md"}'),s={name:"4.资源分区/1.血统与训练/3.心智类/乐园的巫女.md"};function o(d,p,_,l,i,c){return a(),e("div",null,[...p[0]||(p[0]=[r("h1",{id:"乐园的巫女",tabindex:"-1"},[t("乐园的巫女 "),r("a",{class:"header-anchor",href:"#乐园的巫女","aria-label":'Permalink to "乐园的巫女"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023元旦版")])])],-1),n('<h1 id="乐园的巫女-1" tabindex="-1">乐园的巫女 <a class="header-anchor" href="#乐园的巫女-1" aria-label="Permalink to &quot;乐园的巫女&quot;">​</a></h1><p>乐园的巫女</p><p>博丽神社建立在外面世界和幻想乡之间，在两个世界中都能前往博丽神社。<br> 不过，通常无法往来两个世界。<br> 拥有幻想乡常识的人类只能去幻想乡的博丽神社，拥有外面常识的人类只能去外面的博丽神社。<br> 据说外面的博丽神社是个孤寂、无人造访的小神社。<br> 在大结界张开之前，虽然神社也是没什么人到访，但不像现在这么严重。据说自结界张开之后，外面的神社再无人打理过。<br> 博丽神社是专门守护幻想乡不可缺少的大结界的神社。博丽的巫女代代以解决异变为事业</p><p>D级：乐园的巫女<br> 价格：D+600</p><p>你开启灵力能量池，并且获得一种额外的基础用法，你可以在攻击的同时可以消耗1点灵力，令本次攻击获得1点士气加值。</p><p>妖怪退治专家：<br> 作为博丽巫女，她以解决异变为主要工作内容，以降伏妖怪等敌人为主。她是解决异变的专家。一旦异变发生的话，她就会抛掉平时的悠闲，匆忙地查明原因解决事情。并顺便把那些一时心血来潮的家伙给退治掉，你在战斗前，可以宣言此次战斗为退治，当你进行退治时，你的攻击附带法破和短点射特性。</p><p>符卡规则：<br> 妖怪之间的决斗有造成幻想乡崩坏的危险。但是没有了决斗妖怪们的力量就会弱化。因此强力的妖怪（很可能是妖怪贤者）和博丽巫女在命名决斗法案的基础上建立了符卡规则。<br> 名义上，符卡规则是由博丽灵梦提出的，目的是让妖怪们也有可能轻松地打倒巫女。<br> 命名决斗法案的理念是：<br> 妖怪能轻松发动异变<br> 人类能轻松解决异变<br> 否定完全的实力主义<br> 没有东西能胜过美丽与思念<br> 当然，在无限的剧本里，指望对方遵守这些符卡规则多少有些困难了，因此，只能你自己遵守喽～</p><p>你现在在学识技能下开启弹幕专业，你现在可以【决心+学识+专业：弹幕+辅助专业：魔力感知】进行攻击检定，对15米范围内的一个敌人造成远程纯能量伤害 ，以此法进行的攻击具有3L的武器伤害。<br> 你在攻击前以一个自由动作消耗2AP，宣告本次攻击为符卡攻击（如果所使用技艺没有名字，那么自己编，否则需要宣告所用技艺的名字），这会使得本次攻击获得1点附加成功。</p><p>C级：飞翔于天空的不可思议的巫女<br> 价格：C+1200</p><p>在空中飞翔程度的能力：<br> 住在界线上的人类。拥有能在空中飞的程度的能力。<br> 她的能力是在空中飞，也就是无重力。<br> 不管是地球的重力，还是任何的重负，或者由于力量差造成的威胁，这一切对于她而言都是无意义的。<br> 不论身心都轻盈地漂浮于幻想空间中的不可思议的巫女。</p><p>你获得飞行能力，机动性为笨拙，每经历一部进行过一次退治的影片后，该飞行能力提升一级，最多提升至完美。</p><p>巫女的视野：<br> 作为巫女，灵梦可以看见、听见一般人看不见、听不见的神明、或是与神灵对话，因此你获得灵感视觉。</p><p>超乎常人的幸运：<br> 灵梦拥有超乎常人的幸运，她的直觉几乎一定会命中。<br> 她所预测的骰子点数一定是正确的。<br> 她即使看不到脚下的河流也会因为踩到了偶然跃起的鱼而免于落水。<br> 丰聪耳神子认为，灵梦极强的运势源于她无意识地借用了神灵的运势。</p><p>你的机运检定获得1点加值，在进行机运检定时，你也可以消耗2点灵力，借用神灵的运势，使得本次判定再获得1点机运加值。</p><p>B级：终结异变的巫女<br> 价格：B+2400</p><p>零时间移动：<br> 灵梦有着进行零时间移动的能力，虽然天狗和咲夜也有着类似的攻击方式，但是灵梦的攻击模式不同于天狗的高速移动和咲夜的瞬间移动，更加像是通过结界扭曲空间来进行移动。有“灵梦以直线的方式移动，不知不觉的就被包围了”这样的说明。</p><p>你的移动将具有B级时空来源的传送效果</p><p>擦弹：面对无数袭来的弹幕，擦弹往往能提高最大得点，是分数挑战所需的一项基本技能。当然，也是作为解决异变的巫女的必修课，毕竟在华丽且漫天飞舞的弹幕中擦着子弹躲过去，也更加赏心悦目吧。</p><p>你获得B级的措手不及免疫。<br> 你获得基于闪避防御的适应。<br> 以一个移动动作使用，在你的下个回合开始前，如果你收到攻击，你可以以一个反射动作调用这个移动动作进行一次招架，在这次招架时，正常获得招架的伤害抵消数，同时视作你已经移出攻击范围，同时因为灵梦拥有更小的判定点，所以本次招架获得闪避防御上的1DP技艺加值和1附加成功。</p><p>A级：永远的巫女<br> 价格：A+4800</p><p>敏锐的直觉：<br> 灵梦拥有天生的幸运和敏锐，总是依赖直觉来解决异变，她总能察觉到事件的线索与幕后黑手。即使她完全不清楚前因后果，因为她觉得是这样，所以就会是这样<br> 从现在起，当你遇到一些事件的时候，你总能大概察觉到事情的幕后黑手处于什么情况，但你无法确认是谁，这是一个A级的命运效果。<br> 同时，由于你的直觉，任何的偷袭都无法轻易地命中你，因为你总是突然就躲过去了。<br> 你从擦弹中获得的B级免疫措手不及效果提升至A级、</p><p>幻想乡的主角：博丽灵梦是是东方Project系列的第一主角，也是东方系列的代表角色。所有官方游戏整数作的标题画面都是灵梦。同样地，官方漫画里灵梦也均会在封面与第一话登场。她贯穿了东方系列的整个故事线，是东方剧情中最重要的角色之一。</p><p>你获得A级命运来源免疫。<br> 当你进入影片时，你会得到一个有特殊经历的身份，能解释自身能力来源，并附带记忆，附带特殊渠道的人际关系，附带正常人应有的财产，附带符合安排身份的消耗品（需要ST临时安排，无法带出影片），这是一个A级命运来源的特殊身份效果。</p><p>灵异名「隙间女」<br> 大家熟悉的幻想乡的可爱的巫女小姐<br> 射击以及打击的平衡性均良好的标准型角色<br> 若要入门这个世界的格斗推荐使用此角色哦。<br> 灵异攻击是「博丽大结界的隙间」<br> 在空中打开隙间，从中取出漂流物扔向对手的射击技能。<br> 灵梦在打开隙间之后可以另外单独行动，可以进行同时攻击。</p><p>效果：你的攻击范围扩大至敏感范围，且直接获得在移动时进行攻击的能力。</p><p>你获得一个可以存储1000立方米的隙间，该隙间内部视作B级时空来源的异空间，能够在非战斗状态下储存无助或者自愿状态下的活物。</p><p>S级：八百万神的代言人<br> 价格：S+9600</p><p>乐园的巫女：<br> 博丽的巫女是幻想乡秩序的维护者，在幻想乡内受到尊重。<br> 博丽的巫女是什么时候设立的，博丽的巫女是如何确定人选的，先代巫女是谁，官方尚未给出答案。<br> 但博丽的巫女最重要的使命便是，维持幻想乡的秩序。</p><p>你的A级命运来源免疫提升为S级<br> 身为乐园的巫女，你的身份地位将变得无比重要。你的A级特殊身份效果变为S级，你将作为一部影片的主角，其高位存在将无法容忍你因意外死亡，你将成为勇者、救世主等一类有潜力的身份，并附带符合身份的仅在特定情况下具有极大作用的道具。</p><p>博丽结界：</p><p>幻想乡与外界被包围幻想乡的结界分割，其中结界内是幻想的，虚幻的部分，而结界外是现实的部分。这其中的虚幻与现实，是相对于外界人们的科技文明的认知所说的。<br> 灵梦擅长发现空间的间隙，利用其创造结界<br> 运用这一点，她可以创造出没有界线的、循环的空间</p><p>你获得S级时空来源免疫<br> 以一个标准动作启用，选择所有处于你敏感范围的目标，被选中的目标需要以反射豁免对抗你的反射检定，失败则会被拉入博丽结界之中。这是一个S级别、时空来源的异空间效果。<br> 该异空间的大小为你的敏感范围。<br> 持续一场景，当你处于博丽结界中时，博丽结界中除你外的S级别及以下的传送能力失效</p><p>梦想天生：<br> 完全无法碰触到灵梦。不透明的透明人状态。好像是灵梦的究极奥义吧，似乎只是灵梦闭上眼睛，弹幕追踪敌人的位置自动射出而已的样子。顺便一提，刚开始这根本不是什么符卡，不过我给它安上了一个符卡的名字，让灵梦使出来玩了一下。要不然的话根本没有任何胜算。只有这个是天生拥有此能力的灵梦才能使出的符卡。因此名字上也用了天生二字。<br> 一天一次，花费一个迅捷动作，进入梦想天生状态，持续一场景<br> 当你处于梦想天生状态时<br> 你进入灵体状态<br> 每轮可以免疫一次任何伤害，这是一个S级命运来源的无敌效果<br> 你的攻击检定获得【传奇】特性<br> 你的伤害转换为反射豁免<br> 你的所有攻击附带S级的措手不及效果</p><p>技能树：</p><p>梦符「二重结界」</p><p>价格：D+500</p><p>结界是意识的力量。<br> 虽然弹幕本身笔直地飞行着，但结界却将它们歪曲。<br> 如果能用头把两个结界之间补完的话，就将是个非常简单的卡了。</p><p>动作：标准<br> 消耗：2点灵力<br> 射程：15m<br> 目标：单体敌人<br> 你射出一张符卡，随后利用结界的力量将其扭曲，本次攻击附带【破魔5】【高速5】和3dp的速度加值，</p><p>梦境「二重大结界」</p><p>价格：C+1000</p><p>人类过分依赖于视觉情报。<br> 灵梦的结界会妨碍到常识。非常识性的巫女。<br> 即使追着灵梦的身影靠近，灵梦也只会渐渐远去而已。<br> 这种经验不曾有过吗？这就是二重结界的力量。</p><p>动作：标准<br> 消耗：6点灵力<br> 射程：决心*2m<br> 范围：以自己为圆心，射程/2为半径的圆形<br> 目标：范围内全体敌人<br> 你在范围内张开小型结界，随后射出大量弹幕，对范围内所有敌人造成伤害，本次攻击具有【接触攻击】，并附带等值的目盲点数，意志豁免</p><p>境界「二重弹幕结界」</p><p>B+2000</p><p>要是不利用结界就无法避开的攻击。<br> 反过来去利用对手的力量吧。<br> 这样的话，只要不张开结界的话不就避不开了……。</p><p>动作：标准<br> 消耗：10点灵力<br> 射程：75m<br> 范围：以自己为圆心，半径为射程的圆<br> 目标：范围内全部敌人<br> 你展开更强大的结界，令你本次攻击范围内视作C级时空来源的困难地形，持续一轮，对范围内所有敌人造成一次伤害，本次攻击附带【高速5】【破魔5】 ，8加骰，若已有8加骰，则转变为2点附加成功和2点速度加值，</p><p>大结界「博丽弹幕结界」</p><p>A+4000</p><p>和紫的弹幕结界相比的话虽然外表看起来华丽但是内容却不如她。<br> 也是，不管怎么说也只是个人类而已。<br> 已经搞不清楚究竟接下来会发生什么事了。<br> 注意看的话会发现背景也反过来了哦。结界中的。</p><p>动作：标准<br> 消耗：14点灵力<br> 射程：决心*10m<br> 范围：以自身为中心，攻击范围为半径的圆<br> 目标：范围内全部敌人<br> 展开博丽大结界的缩影，对范围内所有敌人进行一次攻击，目标反射豁免，本次攻击你的加骰等级上升一级，最多8加骰。<br> 随后令范围内所有敌人进行一次反射豁免，豁免值等同伤害值，失败则被永久性的放逐到异世界，这是一个A级时空来源的放逐效果；即使成功，其也会在一轮内陷入A级别、诅咒来源的困难地形。</p><p>梦符「封魔阵」</p><p>价格：C+1000</p><p>生成延伸到上方高空的结界。<br> 用加上了诅咒的灵符封印对手行动的术。</p><p>动作：标准<br> 消耗：4点灵力<br> 射程：15m<br> 范围：以自身为中心，射程为半径的圆<br> 目标：范围内所有敌人<br> 你延伸出结界，随后释放大量灵符，对范围所有敌人进行攻击，反射豁免，你可以选择不造成伤害，令本次攻击改为转化为等值精神束缚点数，正常豁免</p><p>神技「八方鬼缚阵」</p><p>价格：B+2000</p><p>生成更加巨大的结界的封魔阵的上位版。<br> 总觉得，看起来好像陷入灵梦所布的阵术当中动弹不得了的样子。<br> 这么说，比起束缚来是不是叫瞬杀会更像？</p><p>动作：标准<br> 消耗：10点灵力<br> 射程：75m<br> 范围：以自身为中心，射程为半径的圆<br> 目标：范围内所有敌人<br> 你在原地布下术阵，范围为你本次技艺的攻击范围，持续一场景，术阵生效期间，令范围内所有敌人每轮开始时与本次攻击的伤害值进行一次反射对抗，对方失败则减少4ap，这是一个B级耗竭效果，同时你的所有攻击获得【高速5】，并附带等值的疲乏异常点数，正常豁免</p><p>神技「八方龙杀阵」</p><p>价格：A+5000</p><p>制成将靠近者全部阻挡的大结界<br> 在以灵梦为中心的广范围内进行攻击<br> 虽然会一个不漏地回击跳进来的敌人<br> 但是因为有宣言所以想拿来反击的意图很容易就能被看破<br> 世间不会有那么顺利的事情<br> 这美丽的灵符的动向灵梦究竟想让谁看到呢。</p><p>动作：标准<br> 消耗：14点灵力<br> 射程：决心*10m<br> 范围：以自身为中心，射程为半径的圆<br> 目标：范围内全部敌人<br> 持续：一场景 你展开一个更巨大的阵术，进行一次施法攻击检定，术阵持续期间，处于范围内的开始回合的所有敌人与本次攻击的成功数进行一次反射豁免对抗，失败则受到差额的纯能量伤害，并在一轮内减少8ap，这是一个A级的耗竭效果。<br> 在术阵中，你的攻击命中目标时，目标需进行一次意志豁免对抗你本次的伤害值，失败则受到A级时空来源的定身效果，持续至术阵结束。</p><p>神灵「梦想封印」</p><p>A+4000</p><p>梦想系基础的最终形态之一。<br> 以大量带有追尾性能的弹幕来封杀敌人，并且是死角很少的技能，不过消费量过高而威力稍低是其缺点。</p><p>动作：标准<br> 消耗：14点灵力<br> 射程：决心*10m<br> 目标：单个敌人<br> 你发出大量弹幕轰杀敌人，令本次攻击检定成功数增加一半，并附带【湮灭】效果，本次攻击的加骰上升一级，最多8加骰，命中后，对方进行一次反射豁免对抗本次攻击的伤害值，失败则受到A级时空来源的即死效果。</p><p>万有灵力定律：</p><p>价格：D+500</p><p>灵力槽比其他角色更长，<br> 灵力最大值更高。<br> 可以使用更多射击攻击与必杀技，<br> 即便防御对手的攻击而导致灵力减少也能轻松一些</p><p>操纵灵气程度的能力：你使用乐园的巫女下属技艺时，消耗的灵力降低你的传奇决心*1点。<br> 你的灵力池上限增加3点，并且血统提供的短点射升级为连射。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',72)])])}const m=b(s,[["render",o]]);export{h as __pageData,m as default};
